package caslcompat

// buildFixtureEventTypes returns comprehensive event type lists for both Phoenix and MOST device types,
// used in the default fixture to populate MessageTranslators.
func buildFixtureEventTypes(phoenixType, mostType string) []UnifiedEventType {
	result := make([]UnifiedEventType, 0, 200)
	result = append(result, phoenixCIDEventTypes(phoenixType)...)
	result = append(result, mostBridgeEventTypes(mostType)...)
	return result
}

// evt is a compact constructor for UnifiedEventType entries.
func evt(dt string, code int, typeEvent string, additionalType int, name string, isAlarm int, uk, ru, en string) UnifiedEventType {
	return UnifiedEventType{
		DeviceType:     dt,
		Code:           code,
		TypeEvent:      typeEvent,
		AdditionalType: additionalType,
		EventByUser:    name,
		IsAlarm:        isAlarm,
		LangUK:         uk,
		LangRU:         ru,
		LangEN:         en,
	}
}

