// phoenixCIDEventTypes returns the comprehensive Phoenix MSSQL event code table.
// Phoenix uses Contact ID protocol codes with additional type-message-based mapping.
func phoenixCIDEventTypes(dt string) []UnifiedEventType {
	base := cidEventTypes(dt)
	// Phoenix-specific extra codes derived from type_message matching
	extra := []UnifiedEventType{
		evt(dt, 130, "E", 1, "PHOENIX_BURGLARY", 1, "Тривога Phoenix", "Тревога Phoenix", "Phoenix burglary alarm"),
		evt(dt, 100, "E", 1, "PHOENIX_MEDICAL", 1, "Медична тривога Phoenix", "Медицинская тревога Phoenix", "Phoenix medical alarm"),
		evt(dt, 302, "E", 0, "PHOENIX_BATT_LOW", 0, "Проблема АКБ Phoenix", "Проблема АКБ Phoenix", "Phoenix battery low"),
		evt(dt, 302, "R", 0, "PHOENIX_BATT_OK", 0, "АКБ Phoenix норма", "АКБ Phoenix норма", "Phoenix battery restore"),
		evt(dt, 383, "E", 1, "PHOENIX_TAMPER", 1, "Тривога тампера Phoenix", "Тревога тампера Phoenix", "Phoenix tamper alarm"),
		evt(dt, 383, "R", 0, "PHOENIX_TAMPER_RESTORE", 0, "Відновлення тампера Phoenix", "Восстановление тампера Phoenix", "Phoenix tamper restore"),
	}
	return append(base, extra...)
}

// mostBridgeEventTypes returns the event code table for MOST/Firebird bridge devices.
// MOST uses SC1 field values which map to a subset of Contact ID codes.
func mostBridgeEventTypes(dt string) []UnifiedEventType {
	return []UnifiedEventType{
		// SC1=1 → fire
		evt(dt, 110, "E", 1, "MOST_FIRE_ALARM", 1, "Пожежна тривога Міст", "Пожарная тревога Мост", "Bridge fire alarm"),
		evt(dt, 110, "R", 1, "MOST_FIRE_RESTORE", 0, "Відновлення пожежі Міст", "Восстановление пожара Мост", "Bridge fire restore"),
		// SC1=1 → also burglary / panic
		evt(dt, 130, "E", 1, "MOST_BURGLARY", 1, "Охоронна тривога Міст", "Охранная тревога Мост", "Bridge burglary alarm"),
		evt(dt, 130, "R", 1, "MOST_BURGLARY_RESTORE", 0, "Відновлення охоронної тривоги Міст", "Восстановление охранной тревоги Мост", "Bridge burglary restore"),
		evt(dt, 120, "E", 1, "MOST_PANIC", 1, "Тривожна кнопка Міст", "Тревожная кнопка Мост", "Bridge panic alarm"),
		evt(dt, 120, "R", 1, "MOST_PANIC_RESTORE", 0, "Відновлення тривожної кнопки Міст", "Восстановление тревожной кнопки Мост", "Bridge panic restore"),
		evt(dt, 100, "E", 1, "MOST_MEDICAL", 1, "Медична тривога Міст", "Медицинская тревога Мост", "Bridge medical alarm"),
		evt(dt, 151, "E", 1, "MOST_GAS", 1, "Газова тривога Міст", "Газовая тревога Мост", "Bridge gas alarm"),
		evt(dt, 151, "R", 1, "MOST_GAS_RESTORE", 0, "Відновлення газової тривоги Міст", "Восстановление газовой тревоги Мост", "Bridge gas restore"),
		// SC1=2,3 → fault (zone break / short circuit)
		evt(dt, 380, "E", 0, "MOST_ZONE_FAULT", 0, "Несправність зони Міст", "Неисправность зоны Мост", "Bridge zone fault"),
		evt(dt, 380, "R", 0, "MOST_ZONE_FAULT_RESTORE", 0, "Відновлення несправності зони Міст", "Восстановление неисправности зоны Мост", "Bridge zone fault restore"),
		evt(dt, 331, "E", 0, "MOST_LOOP_BREAK", 1, "Обрив шлейфу Міст", "Обрыв шлейфа Мост", "Bridge sensor loop break"),
		evt(dt, 331, "R", 0, "MOST_LOOP_BREAK_RESTORE", 0, "Відновлення обриву шлейфу Міст", "Восстановление обрыва шлейфа Мост", "Bridge sensor loop restore"),
		evt(dt, 332, "E", 0, "MOST_LOOP_SHORT", 1, "КЗ шлейфу Міст", "КЗ шлейфа Мост", "Bridge sensor loop short circuit"),
		evt(dt, 332, "R", 0, "MOST_LOOP_SHORT_RESTORE", 0, "Відновлення КЗ шлейфу Міст", "Восстановление КЗ шлейфа Мост", "Bridge sensor loop short circuit restore"),
		// SC1=5,9,13,17 → restore
		evt(dt, 110, "R", 1, "MOST_RESTORE", 0, "Відновлення тривоги Міст", "Восстановление тревоги Мост", "Bridge alarm restore"),
		// SC1=10 → arm
		evt(dt, 401, "E", 0, "MOST_ARM", 0, "Постановка під охорону Міст", "Постановка под охрану Мост", "Bridge armed"),
		evt(dt, 401, "R", 0, "MOST_DISARM", 0, "Зняття з охорони Міст", "Снятие с охраны Мост", "Bridge disarmed"),
		// SC1=11,14,18 → disarm
		evt(dt, 402, "E", 0, "MOST_DISARM", 0, "Зняття з охорони Міст", "Снятие с охраны Мост", "Bridge disarmed"),
		evt(dt, 402, "R", 0, "MOST_ARM", 0, "Постановка під охорону Міст", "Постановка под охрану Мост", "Bridge armed"),
		// SC1=12 → offline / online
		evt(dt, 359, "E", 0, "MOST_DEVICE_OFFLINE", 1, "Немає зв'язку Міст", "Нет связи Мост", "Bridge device offline"),
		evt(dt, 359, "R", 0, "MOST_DEVICE_ONLINE", 0, "Зв'язок Міст відновлено", "Связь Мост восстановлена", "Bridge device online"),
		// AC power
		evt(dt, 301, "E", 0, "MOST_AC_LOSS", 0, "Втрата живлення Міст", "Потеря питания Мост", "Bridge AC loss"),
		evt(dt, 301, "R", 0, "MOST_AC_RESTORE", 0, "Живлення Міст відновлено", "Питание Мост восстановлено", "Bridge AC restore"),
		evt(dt, 302, "E", 0, "MOST_BATT_LOW", 0, "Низький заряд АКБ Міст", "Низкий заряд АКБ Мост", "Bridge battery low"),
		evt(dt, 302, "R", 0, "MOST_BATT_RESTORE", 0, "АКБ Міст відновлено", "АКБ Мост восстановлено", "Bridge battery restore"),
		// tamper
		evt(dt, 383, "E", 0, "MOST_TAMPER", 1, "Тампер Міст", "Тампер Мост", "Bridge tamper"),
		evt(dt, 383, "R", 0, "MOST_TAMPER_RESTORE", 0, "Відновлення тампера Міст", "Восстановление тампера Мост", "Bridge tamper restore"),
		// test
		evt(dt, 602, "E", 0, "MOST_TEST", 0, "Тест Міст", "Тест Мост", "Bridge test"),
		// partial arm/disarm (SC1=14,18)
		evt(dt, 404, "E", 2, "MOST_PARTIAL_DISARM", 0, "Часткове зняття групи Міст", "Частичное снятие группы Мост", "Bridge partial disarm"),
		evt(dt, 403, "E", 2, "MOST_AUTO_DISARM", 0, "Автоматичне зняття групи Міст", "Автоматическое снятие группы Мост", "Bridge auto disarm"),
	}
}
